import React, { useState, useEffect } from 'react';
import './App.css';
import Topo from "./componentes/Topo";
import Rodape from "./componentes/Rodape";

function App() {
  const [produtos, setProdutos] = useState([]);
  const [carrinho, setCarrinho] = useState([]);
  const [etapa, setEtapa] = useState('vitrine'); 
  const [modoCadastro, setModoCadastro] = useState(false);
  const [usuario, setUsuario] = useState(null);
  const [formaPagamento, setFormaPagamento] = useState('');
  const [pedidoFinalizado, setPedidoFinalizado] = useState(null);
  const [formData, setFormData] = useState({ nome:'', email:'', senha:'', cpf:'', telefone:'', cep:'', endereco:'' });

  useEffect(() => {
    fetch("http://localhost:3001/produtos").then(res => res.json()).then(d => setProdutos(d));
  }, []);

  const totalProd = carrinho.reduce((acc, i) => acc + (i.valor * i.qtd), 0);
  const valorFrete = formaPagamento === 'pix' ? 0 : 15.00;

 const handleAuth = () => {
  const rota = modoCadastro ? 'cadastrar' : 'login';
  
  fetch(`http://localhost:3001/${rota}`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(formData)
  })
  .then(async res => {
    const dados = await res.json();
    if (!res.ok) {
      // Aqui pegamos a mensagem real do MySQL que o Node enviou
      throw new Error(dados.message || "Erro desconhecido");
    }
    return dados;
  })
  .then(user => { 
    setUsuario(user); 
    setEtapa('checkout'); 
  })
  .catch((err) => {
    // ESSE ALERT VAI TE DAR A RESPOSTA FINAL
    alert("ERRO REAL DO BANCO: " + err.message);
    console.error("Erro completo:", err);
  });
};
  const finalizar = () => {
    const numP = Math.floor(Math.random() * 900000);
    fetch("http://localhost:3001/finalizar-pedido", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ id_pedido: numP, itens: carrinho })
    })
    .then(() => {
      setPedidoFinalizado({ numero: numP, total: totalProd + valorFrete, pagamento: formaPagamento });
      setEtapa('sucesso');
      setCarrinho([]);
    });
  };

  return (
    <div className="App">
      <Topo totalItens={carrinho.length} abrirCarrinho={() => setEtapa('carrinho')} temPedido={!!pedidoFinalizado} />
      
      <main className="conteudo-principal">
        {etapa === 'vitrine' && (
          <div className="grid-produtos">
            {produtos.map(p => (
              <div key={p.id} className="card">
                <img src={p.imagem_url} alt={p.produto} />
                <h3>{p.produto}</h3>
                <p>R$ {parseFloat(p.valor).toFixed(2)}</p>
                <button onClick={() => { setCarrinho([...carrinho, {...p, qtd:1}]); setEtapa('carrinho'); }}>Comprar</button>
              </div>
            ))}
          </div>
        )}

        {etapa === 'carrinho' && (
          <div className="container-venda">
            <h2>🛒 Carrinho</h2>
            {carrinho.map(i => <div className="item-lista"><span>{i.produto}</span><span>R$ {i.valor}</span></div>)}
            <h3>Total: R$ {totalProd.toFixed(2)}</h3>
            <button className="btn-p" onClick={() => setEtapa('login')}>Ir para Identificação</button>
            <button className="btn-v" onClick={() => setEtapa('vitrine')}>Voltar</button>
          </div>
        )}

        {etapa === 'login' && (
          <div className="container-venda">
            <h2>{modoCadastro ? "📝 Cadastro" : "🔐 Login"}</h2>
            <input className="in-v" type="email" placeholder="E-mail" onChange={e => setFormData({...formData, email: e.target.value})} />
            <input className="in-v" type="password" placeholder="Senha" onChange={e => setFormData({...formData, senha: e.target.value})} />
            {modoCadastro && (
              <>
                <input className="in-v" type="text" placeholder="Nome" onChange={e => setFormData({...formData, nome: e.target.value})} />
                <input className="in-v" type="text" placeholder="CPF" onChange={e => setFormData({...formData, cpf: e.target.value})} />
                <input className="in-v" type="text" placeholder="Endereço" onChange={e => setFormData({...formData, endereco: e.target.value})} />
              </>
            )}
            <button className="btn-p" onClick={handleAuth}>{modoCadastro ? "Cadastrar" : "Entrar"}</button>
            <p onClick={() => setModoCadastro(!modoCadastro)} className="link-troca">{modoCadastro ? "Voltar ao Login" : "Criar Conta"}</p>
          </div>
        )}

        {etapa === 'checkout' && (
          <div className="container-venda">
            <h2>📍 Entrega para {usuario?.nome}</h2>
            <p>{usuario?.endereco} - {usuario?.cep}</p>
            <select className="in-v" onChange={e => setFormaPagamento(e.target.value)}>
              <option value="">Forma de Pagamento...</option>
              <option value="pix">Pix (Frete Grátis)</option>
              <option value="cartao">Cartão (Frete R$ 15,00)</option>
            </select>
            <div className="resumo-f">
              <p>Pedido: R$ {totalProd.toFixed(2)}</p>
              <p>Frete: R$ {valorFrete.toFixed(2)}</p>
              <h3>Total: R$ {(totalProd + valorFrete).toFixed(2)}</h3>
            </div>
            <button className="btn-p" onClick={finalizar}>Confirmar Pedido</button>
          </div>
        )}

        {etapa === 'sucesso' && (
          <div className="alerta-s">
            <h2>✅ Sucesso! Pedido #{pedidoFinalizado.numero}</h2>
            <p>Valor: R$ {pedidoFinalizado.total.toFixed(2)}</p>
            <button onClick={() => setEtapa('vitrine')}>Nova Compra</button>
          </div>
        )}
      </main>
      <Rodape />
    </div>
  );
}

export default App;
